function getAverage(numbers) {
  let total = 0;

  for (let i = 0; i <= numbers.length; i++) {
    total += numbers[i];
  }

  return total / numbers.length;
}

output:
Issue: The loop uses <= numbers.length, causing an off-by-one error. On the last iteration, numbers[numbers.length] is undefined, resulting in NaN. The function also doesn't handle an empty array.

Fixed code:

function getAverage(numbers) {
  if (numbers.length === 0) {
    return 0;
  }

  const total = numbers.reduce((sum, value) => sum + value, 0);
  return total / numbers.length;
}

